const body = $input.first().json.body || {};
if (!body.project_id) { return [{ json: { valid: false, error: 'project_id obligatorio' } }]; }
if (!body.phase_key) { return [{ json: { valid: false, error: 'phase_key obligatorio' } }]; }
const valid = ['demolicion','replanteo','albanileria','instalaciones_electricas','instalaciones_fontaneria','instalaciones_climatizacion','aislamiento_carpinteria','pavimentos_revestimientos','sanitarios_griferia','pintura','recepcion_provisional','otros'];
if (!valid.includes(body.phase_key)) { return [{ json: { valid: false, error: 'phase_key debe ser uno de: ' + valid.join(', ') } }]; }

const templates = {
  demolicion: [
    { id: 'd1', label: 'Apeo de elementos a conservar', description: 'Verificar apuntalamiento adecuado de elementos NO derribados.' },
    { id: 'd2', label: 'Acotamiento zona de obra', description: 'Cerramiento perimetral, cartel de obra, salida emergencia despejada.' },
    { id: 'd3', label: 'Gestion residuos RCD', description: 'Contenedor autorizado + ficha de gestion de residuos.' },
    { id: 'd4', label: 'Inspeccion post-demolicion', description: 'Verificar ausencia de patologias ocultas: humedades, instalaciones obsoletas, amianto.' },
    { id: 'd5', label: 'Estado estructura tras demolicion', description: 'Comprobar elementos portantes restantes sin danos.' }
  ],
  replanteo: [
    { id: 'r1', label: 'Replanteo coincide con plano', description: 'Medidas in situ vs medidas del plano: tolerancia +/- 1cm.' },
    { id: 'r2', label: 'Niveles confirmados', description: 'Cota suelo terminado coincide en todos los espacios.' },
    { id: 'r3', label: 'Pasos de instalaciones marcados', description: 'Bajantes, rozas, cuadros electricos y patinillos identificados antes de cerrar tabiques.' },
    { id: 'r4', label: 'Aprobacion cliente del replanteo', description: 'Cliente firma acta de replanteo o confirma por email.' }
  ],
  albanileria: [
    { id: 'a1', label: 'Tabiques a plomada y escuadra', description: 'Tolerancia plomada 5mm/2m. Escuadra 90 +/- 0.5 grados.' },
    { id: 'a2', label: 'Encuentros con techo y suelo', description: 'Sin holguras visibles, sellado correcto.' },
    { id: 'a3', label: 'Refuerzos en huecos', description: 'Cargaderos de huecos (puertas/ventanas) correctamente dispuestos.' },
    { id: 'a4', label: 'Tabiques de yeso laminado', description: 'Estructura cada 60cm max. Cinta + masilla en juntas. Doble placa en paramentos humedos.' },
    { id: 'a5', label: 'Acustica DB-HR', description: 'Lana mineral en cavidades. Bandas elasticas en arranque.' }
  ],
  instalaciones_electricas: [
    { id: 'e1', label: 'REBT cumplido', description: 'Diferencial 30mA en cuadro. Magnetotermicos por circuito segun grado electrificacion.' },
    { id: 'e2', label: 'Tomas en bano clasificadas', description: 'Volumen 0/1 sin tomas. Volumen 2 IP44. Volumen 3 IP21 minimo.' },
    { id: 'e3', label: 'Secciones de cable', description: '1.5mm2 alumbrado, 2.5mm2 tomas generales, 4mm2 cocina, 6mm2 termo y AC.' },
    { id: 'e4', label: 'Boletin de instalador autorizado', description: 'Firmado y registrado en industria CCAA.' },
    { id: 'e5', label: 'Pruebas funcionales', description: 'Cada toma + cada interruptor probado bajo carga.' }
  ],
  instalaciones_fontaneria: [
    { id: 'f1', label: 'Prueba de presion en frio', description: 'Carga 1.5x presion de servicio durante 30 minutos sin perdida.' },
    { id: 'f2', label: 'Llaves de corte por aparato', description: 'Cada lavabo, inodoro, ducha, lavadora, lavavajillas con llave individual.' },
    { id: 'f3', label: 'Pendientes de desague', description: '1.5%-3% en horizontal. Sifones individuales 25mm minimo.' },
    { id: 'f4', label: 'Materiales certificados', description: 'PER multicapa o PEX. NUNCA tuberia de plomo. AENOR + sello agua potable.' },
    { id: 'f5', label: 'Aislamiento en ACS', description: 'Coquilla aislante segun RITE en montantes.' }
  ],
  instalaciones_climatizacion: [
    { id: 'c1', label: 'RITE cumplido', description: 'IT 1.2 eficiencia, IT 1.3 ventilacion. Memoria tecnica firmada.' },
    { id: 'c2', label: 'Carga termica calculada', description: 'Calculo por habitacion. Frigorias/calorias coherentes con superficie + orientacion.' },
    { id: 'c3', label: 'Desagues condensacion', description: 'Conducidos a bajante con sifon. Sin desagotar a fachada o terraza vecina.' },
    { id: 'c4', label: 'Ventilacion DB-HS3', description: 'Caudales minimos por estancia. Sistema hibrido o mecanico segun proyecto.' }
  ],
  aislamiento_carpinteria: [
    { id: 'i1', label: 'Aislamiento envolvente CTE HE1', description: 'Espesor minimo segun zona climatica. Continuidad sin puentes termicos.' },
    { id: 'i2', label: 'Carpinteria exterior con marcado CE', description: 'Etiqueta visible. U <= 1.6 W/m2K. RPT en perfiles aluminio.' },
    { id: 'i3', label: 'Sellado perimetral ventanas', description: 'Espuma + cinta multifuncion + sellado interior con masilla acrilica.' },
    { id: 'i4', label: 'Persianas con cajones aislados', description: 'Sin perdida termica. Acceso registrable para mantenimiento.' }
  ],
  pavimentos_revestimientos: [
    { id: 'p1', label: 'Soporte preparado', description: 'Limpio, plano (regla 2m, hueco max 3mm), seco (humedad <3%).' },
    { id: 'p2', label: 'Juntas de dilatacion', description: 'En perimetro y cada 25-50m2 segun material.' },
    { id: 'p3', label: 'Pendientes en zonas humedas', description: '1.5% minimo hacia desague.' },
    { id: 'p4', label: 'Material conforme a proyecto', description: 'Coincide con design_option seleccionado y materials aprobados.' },
    { id: 'p5', label: 'Repaso visual', description: 'Sin piezas rotas, encuentros limpios, juntas uniformes.' }
  ],
  sanitarios_griferia: [
    { id: 's1', label: 'Sanitarios alineados y nivelados', description: 'Tolerancia 1cm respecto a paredes adyacentes.' },
    { id: 's2', label: 'Fijaciones con silicona neutra', description: 'No silicona acetica (ataca metales). Cordon continuo.' },
    { id: 's3', label: 'Caudales y temperaturas correctos', description: 'Caudal griferia 6-9 L/min. Termostatico estable a 38C +/- 2C.' },
    { id: 's4', label: 'Sin fugas tras 24h', description: 'Comprobacion visual y mancha papel bajo desagues.' }
  ],
  pintura: [
    { id: 'pt1', label: 'Soporte plano y limpio', description: 'Sellado de fisuras. Imprimacion. Sin polvo.' },
    { id: 'pt2', label: 'Numero de manos correcto', description: 'Minimo 2 manos. Plastico mate exterior, satinado en bano/cocina.' },
    { id: 'pt3', label: 'Acabado uniforme', description: 'Sin marcas de rodillo, sin gotas, sin aureolas.' },
    { id: 'pt4', label: 'Repaso de cantos', description: 'Esquinas, marcos, zocalos limpios sin manchar.' }
  ],
  recepcion_provisional: [
    { id: 'rp1', label: 'Limpieza fin de obra', description: 'Sin restos de yeso, polvo, embalajes. Pulidos y lavados.' },
    { id: 'rp2', label: 'Pruebas funcionales completas', description: 'Cada interruptor, grifo, electrodomestico funcional.' },
    { id: 'rp3', label: 'Documentacion entregada', description: 'Boletines, certificados, manuales, garantias.' },
    { id: 'rp4', label: 'Acta de recepcion firmada', description: 'Fecha entrega, lista de incidencias pendientes (anexo).' },
    { id: 'rp5', label: 'Repaso visual con cliente', description: 'Recorrido habitacion por habitacion, registrar pegas en aftercare_incidents.' }
  ],
  otros: []
};

const items = (templates[body.phase_key] || []).map(t => ({
  ...t, status: 'pending', evidence_url: null, comment: null, checked_at: null
}));

return [{ json: {
  valid: true,
  project_id: body.project_id,
  phase_key: body.phase_key,
  generated_by: body.generated_by || 'arquitecto',
  items: items,
  notes: (body.notes || '').toString().slice(0, 500)
}}];
